Object.entries(NEW_LANGS).forEach(([lng, b]) => {
  i18n.addResourceBundle(lng, "translation", b.translation, true, true);
  if (b.extra) {
    Object.entries(b.extra).forEach(([ns, val]) => {
      i18n.addResourceBundle(lng, "translation", { [ns]: val }, true, true);
    });
  }
});

export default i18n;

